it = iter(sys.stdin.read().split())
n = int(next(it))
stack = [int(next(it)) for _ in range(n)]

def insert_at_bottom(stack, item):
    if not stack:
        stack.append(item)
    else:
        temp = stack.pop()
        insert_at_bottom(stack, item)
        stack.append(temp)

def reverse_stack(stack):
    if not stack:
        return
    temp = stack.pop()
    reverse_stack(stack)
    insert_at_bottom(stack, temp)

reverse_stack(stack)
for num in stack:
    print(num)

