#include <bits/stdc++.h>
using namespace std;

void insert_at_bottom(vector<int>& stack, int item) {
    if (stack.empty()) {
        stack.push_back(item);
    } else {
        int temp = stack.back();
        stack.pop_back();
        insert_at_bottom(stack, item);
        stack.push_back(temp);
    }
}

void reverse_stack(vector<int>& stack) {
    if (stack.empty()) {
        return;
    }
    int temp = stack.back();
    stack.pop_back();
    reverse_stack(stack);
    insert_at_bottom(stack, temp);
}

int main() {
    int n;
    if (!(cin >> n)) return 0;
    vector<int> stack;
    for (int i = 0; i < n; i++) {
        int num;
        cin >> num;
        stack.push_back(num);
    }
    reverse_stack(stack);
    for (int num : stack) {
        cout << num << endl;
    }
    return 0;
}
